import React , {Component} from 'react';
import './KresizeTrigger.css'

class KresizeTrigger extends Component {
    
    constructor(props) {
        super(props);

        this.state = {
            style : {
                width       : this.props.size.width,
                height      : this.props.size.height,
                marginLeft  : this.props.pos.x,
                marginTop   : this.props.pos.y,
                cursor      : this.props.cursor,
            }
        };

        this.isMouseDown    =  false;
        this.prevMousePos   = {x: 0, y: 0};

        this.onMouseDown    =  this.onMouseDown.bind(this);
        this.onMouseUp      =  this.onMouseUp.bind(this);
        this.onMouseMove    =  this.onMouseMove.bind(this)
    }

    componentDidMount() {
        document.addEventListener('mousemove', this.onMouseMove);
    }

    componentWillUnmount() {
        document.removeEventListener('mousemove', this.onMouseMove);
    }

    onMouseDown(e) {
        this.prevMousePos   = {x : e.clientX , y: e.clientY};
        this.isMouseDown    = true;
        //console.log("down"+ this.currentPos.x);
    }

    onMouseUp(e) {
        this.isMouseDown    = false;
        this.prevMousePos   = {x: 0, y: 0};
        //console.log("up"+ this.currentPos.x);
    }


    updateState() {
        this.setState({
            style : {
                width       : this.props.size.width,
                height      : this.props.size.height,
                marginLeft  : this.props.pos.x,
                marginTop   : this.props.pos.y,
                cursor      : this.props.cursor,
            }
        });
    }

    onMouseMove(e) {
        
        if(this.isMouseDown == true) {
            //console.log("move" + this.currentPos.x);
            let offSet = {x : e.clientX - this.prevMousePos.x, y: e.clientY - this.prevMousePos.y};
            this.props.onResizeWindow(e, offSet);
            this.prevMousePos   = {x : e.clientX , y: e.clientY};

            this.updateState();
        }
    }


    render() {
        return (
            <div className="kresizetrigger" 
                style={this.state.style}
                onMouseDown={this.onMouseDown}
                onMouseUp={this.onMouseUp}>

                    {this.props.children}
                    
            </div>
        );
    }
}

export default KresizeTrigger;