import React , {Component} from 'react';
import KtreeItem from './KtreeItem';
import './KtreeView.css'

class KtreeView extends Component {

    constructor(props) {
        super(props);

        this.state = {
            style : {
                width  : this.props.size.width,
                height : this.props.size.height,
            },
            data : this.props.data,
        };

    }

    updateState() {
        this.setState({
            style : {
                width  : this.props.size.width,
                height : this.props.size.height,
            },
            data : this.props.data,
        });
    }


    render() {
        return (
            <div className="ktreeView"
                style={this.state.style}>
                    <KtreeItem child={this.state.data.child} 
                        lable={this.state.data.lable} 
                        level={0}/>
            </div>
        );
    }
}

export default KtreeView;