import React , {Component} from 'react';
import './KleftContent.css';
import KresizeTrigger from './KresizeTrigger'
import KtreeView from './KtreeView'

class KleftContent extends Component {

    constructor(props) {
        super(props);

        this.width       = this.props.size.width;
        this.height      = this.props.size.height;
        
        this.data = {
                lable : "root",
                child : [
                    {
                        lable : "name1",
                        child : [
                            {
                                lable : "name1.1",
                                child : [
                                    {
                                        lable : "name1.1.1",
                                        child : []
                                    },
                                    {
                                        lable : "name1.1.2",
                                        child : []
                                    },
                                    {
                                        lable : "name1.1.3",
                                        child : []
                                    },
                                ]
                            },
                            {
                                lable : "name1.2",
                                child : []
                            },
                            {
                                lable : "name1.3",
                                child : []
                            },
                        ]
                    },
                    {
                        lable : "name2",
                        child : []
                    },
                    {
                        lable : "name3",
                        child : [
                            {
                                lable : "name3.1",
                                child : []
                            },
                            {
                                lable : "name3.2",
                                child : []
                            },
                            {
                                lable : "name3.3",
                                child : []
                            },
                        ]
                    },
                    {
                        lable : "name4",
                        child : []
                    },
                    {
                        lable : "name5",
                        child : []
                    },
                ]
        };

        this.state = {
            style : {
                width       : this.width,
                height      : this.height,
                marginLeft  : this.props.pos.x,
                marginTop   : this.props.pos.y,
            },
            dataTreeView : this.data,
        };



        this.onResizeWindow     = this.onResizeWindow.bind(this);
        this.kresizeTriggerIns  = React.createRef();
        this.ktreeViewIns       = React.createRef();
    }

    updateState() {
        this.setState({
            style : {
                width       : this.width,
                height      : this.props.size.height,
                marginLeft  : this.props.pos.x,
                marginTop   : this.props.pos.y,
            }
        });

        this.kresizeTriggerIns.current.updateState();
        this.ktreeViewIns.current.updateState();
    }

    onResizeWindow(e,offSet) {
        this.width = this.width + offSet.x;
        this.updateState();
        this.kresizeTriggerIns.current.updateState();
        this.ktreeViewIns.current.updateState();
    }

    render() {
        return (
            <div className="kleftContent"
                style={this.state.style}>

                    <KtreeView size={{width : this.state.style.width, height: this.state.style.height}}
                        data={this.state.dataTreeView}
                        ref={this.ktreeViewIns}/>

                    <KresizeTrigger size={{width: 7, height: this.state.style.height}}
                        pos={{x: this.state.style.width, y: 0}} 
                        onResizeWindow={this.onResizeWindow}
                        cursor={"w-resize"}
                        ref={this.kresizeTriggerIns}>
                            <div style={{width: 2, height : this.state.style.height, backgroundColor: "black"}}></div>
                    </KresizeTrigger>


            </div>
        );
    }
}

export default KleftContent;