import React , {Component} from 'react';
import './KtreeItem.css';

class KtreeItem extends Component {

    constructor(props) {
        super(props);

        this.toggle             = true;
        this.display            = "block";

        this.state = {
            lable : this.props.lable,
            child : this.props.child,
            childStyle : {
                display : this.display,
            }
        };

        this.onMouseDown    =  this.onMouseDown.bind(this);
    }

    updateState() {
        this.setState({
            lable : this.props.lable,
            child : this.props.child,
            childStyle : {
                display : this.display,
            }
        });
    }

    onMouseDown(e) {
        if(this.toggle == true) {
            this.display   = "none";
        }
        else {
            this.display   = "block";
        }

        this.toggle = !this.toggle;
        this.updateState();
    }

    render() {
        return (
            <div style={{marginTop:5}} className="ktreeItem">
                <div className="ktreeItemlbl" 
                    style={{marginLeft : this.props.level * 10}}> 

                        <span className="collapseTrigger"
                            onClick={this.onMouseDown}>
                                {
                                    this.toggle == true ? 
                                        <svg width={10} height={10}>
                                            <polygon points="0,0 10,0 5,10" fill="red"/>
                                        </svg> 
                                        : 
                                        <svg width={10} height={10}>
                                            <polygon points="0,0 0,10 10,5" fill="green"/>
                                        </svg>
                                }
                                
                        </span>

                        <span>{this.state.lable}</span> 

                </div>

                <div className="ktreeItemChild"
                    style={this.state.childStyle}>
                        {this.state.child.map((el,i) => <KtreeItem ref={this.childItemIns} child={el.child} lable={el.lable} level={this.props.level + 1}/>)}
                </div>

            </div>
        );
    }
}

export default KtreeItem;