import React , {Component} from 'react';
import './Ktitlebar.css'

class Ktitlebar extends Component {

    constructor(props) {
        super(props);
        this.state = {
            style : {
                width  : this.props.width,
                height : this.props.height,
            }
        };

        this.onMouseDown    =  this.onMouseDown.bind(this);
        this.onMouseUp      =  this.onMouseUp.bind(this);
        this.onMouseMove    =  this.onMouseMove.bind(this);

        this.isMouseDown    =  false;
        this.currentPos     =  {x: this.props.wndPos.x, y: this.props.wndPos.y}; // the position of parent windows
        this.offset         =  {x: 0, y: 0};
    }

    updateState() {
        this.setState({
            style : {
                width  : this.props.width,
                height : this.props.height,
            }
        });
    }

    componentDidMount() {
        document.addEventListener('mousemove', this.onMouseMove);
    }

    componentWillUnmount() {
        document.removeEventListener('mousemove', this.onMouseMove);
    }

    onMouseDown(e) {
        this.offset      = {x : e.clientX - this.currentPos.x, y: e.clientY - this.currentPos.y};
        this.isMouseDown = true;
        //console.log("down"+ this.currentPos.x);
    }

    onMouseUp(e) {
        this.isMouseDown = false;
        //console.log("up"+ this.currentPos.x);
    }

    onMouseMove(e) {
        
        if(true) {
            if(this.isMouseDown == true) {
                //console.log("move" + this.currentPos.x);
                this.currentPos = {x: e.clientX - this.offset.x, y: e.clientY - this.offset.y};
                this.props.onMoveWindow(e, this.currentPos);
                this.updateState();
            } 
        }
    }

    render() {
        return (
            <div className="ktitlebar" 
                style={this.state.style}
                onMouseDown={this.onMouseDown}
                onMouseUp={this.onMouseUp}>

            </div>
        );
    }
}


export default Ktitlebar;