import React , {Component} from 'react';
import './Kwindows.css';
import Ktitlebar        from './Ktitlebar'
import KresizeTrigger   from './KresizeTrigger'
import KleftContent     from './KleftContent'


class Kwindows extends Component {

    constructor(props) {
        super(props);
        this.wndPos         = {x: 100, y: 200};
        this.wndSize        = {width: 500, height: 220};
        this.wndtrans       = "translate3d(" + this.wndPos.x + "px," + this.wndPos.y + "px,0)";
        this.ktitlebarIns   = React.createRef();
        this.kleftContentIns   = React.createRef();
        this.state = {
            style : {
                ...this.wndSize,
                transform : this.wndtrans,
            } 
        };

        this.onMoveWindow    = this.onMoveWindow.bind(this);
        this.onResizeWindow  = this.onResizeWindow.bind(this);
        this.onWindowChanged = this.onWindowChanged.bind(this);
    }

    updateState() {
        this.setState({
            style : {
                ...this.wndSize,
                transform : this.wndtrans,
            } 
        });
    }

    onWindowChanged(isChanged) {
        this.isWndChanged = isChanged;
    }

    onResizeWindow(e, offSet) {
        this.wndSize = {width: this.wndSize.width + offSet.x, height: this.wndSize.height + offSet.y};
        this.updateState();
        this.ktitlebarIns.current.updateState();
        this.kleftContentIns.current.updateState();
    }

    onMoveWindow(e, newPos) {
        this.wndPos     = newPos;
        this.wndtrans   = "translate3d(" + newPos.x + "px," + newPos.y + "px,0)";
        this.updateState();
    }


    render() {
        return (
            <div className="kwindow" style={this.state.style}>
                <Ktitlebar width={this.state.style.width} height={20} 
                    wndPos={this.wndPos}
                    onMoveWindow={this.onMoveWindow}
                    ref={this.ktitlebarIns}/>

                <KleftContent size={{width: this.wndSize.width / 4, height: this.wndSize.height - 20}}
                    pos={{x:0, y:20}}
                    ref={this.kleftContentIns}>
                        
                </KleftContent>

                <KresizeTrigger size={{width: 10, height: 10}}
                    pos={{x: this.wndSize.width - 10, y: this.wndSize.height - 10}} 
                    onResizeWindow={this.onResizeWindow}
                    cursor={"nw-resize"}>

                        <svg width="10" height="10">
                            <polygon points="10,0 0,10 10,10" fill="green" />
                        </svg>

                </KresizeTrigger>
            </div>
        );

    }
}

export default Kwindows;